import mailer from "../../utils/mailer";

export default async (req, res) => {
  if (!(req.method === "POST")) {
    return res.status(501).end();
  }
  // console.log("lol");
  // const { name, email, phone, message } = req.body;
  const { name } = req.body;

  // await mailer({});

  res.status(200).json(name);
};
